INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: Types of Adjectives (25 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'adjectives', 'beginner', '"The _____ sun is shining."', '["bright", "brightly", "brightness", "brighten"]', 0, 'Adjective describes noun (sun). "bright" = adjective. "brightly" = adverb. Pattern: adjective + noun.', 'easy'),

('foundation', 'adjectives', 'beginner', '"She is a _____ teacher."', '["kind", "kindly", "kindness", "kinder"]', 0, 'Adjective describes noun (teacher). "kind" = adjective. "kindly" = adverb. Pattern: adjective + noun.', 'easy'),

('foundation', 'adjectives', 'beginner', '"I have _____ books."', '["many", "much", "more", "most"]', 0, 'Quantitative adjective: many (countable plural). "much" = uncountable. Pattern: many + plural noun.', 'easy'),

('foundation', 'adjectives', 'beginner', '"_____ car is this?"', '["Which", "What", "Where", "Who"]', 0, 'Interrogative adjective: Which (asks to choose). Pattern: Which + noun + verb?', 'easy'),

('foundation', 'adjectives', 'beginner', '"_____ is my book."', '["This", "These", "Those", "That"]', 0, 'Demonstrative adjective: This (near, singular). Pattern: This/That + singular noun. Near = this.', 'easy'),

('foundation', 'adjectives', 'beginner', '"I ate _____ apple."', '["one", "two", "three", "many"]', 0, 'Numeral adjective: one (exact number). "an apple" = one apple. Pattern: number + noun.', 'easy'),

('foundation', 'adjectives', 'beginner', '"_____ students are present?"', '["How many", "How much", "What", "Which"]', 0, 'Quantitative: How many (countable). "How much" = uncountable. Pattern: How many + plural noun?', 'easy'),

('foundation', 'adjectives', 'beginner', '"This is _____ book."', '["my", "mine", "I", "me"]', 0, 'Possessive adjective: my (before noun). "mine" = possessive pronoun (no noun). Pattern: my + noun.', 'easy'),

('foundation', 'adjectives', 'beginner', 'Which is a descriptive adjective?', '["beautiful", "three", "my", "this"]', 0, 'Descriptive = describes quality (beautiful, tall, smart). Number = three. Possessive = my. Demonstrative = this.', 'easy'),

('foundation', 'adjectives', 'beginner', 'Which is a possessive adjective?', '["her", "she", "hers", "herself"]', 0, 'Possessive adjective (before noun): my, your, his, her, its, our, their. "hers" = pronoun. "she" = subject. Pattern: possessive + noun.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'adjectives', 'beginner', 'What is wrong? "I have money much."', '["Use: much money (order)", "Use: many instead of much", "Use: more instead of much", "Nothing wrong"]', 0, 'Adjective before noun. Correct: "I have much money." Pattern: quantitative adjective + noun. English = adjective comes first!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose correct: "_____ children are playing?"', '["How many", "How much", "What", "Which"]', 0, 'Countable = How many. "children" = countable plural. "How much" = uncountable. Pattern: How many + countable?', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "These is my house."', '["Use: This instead of These", "Use: are instead of is", "Use: Those instead of These", "Both A and B"]', 3, 'Two fixes: "These" (plural) needs "are." OR singular "house" needs "This." Both valid: "This is my house" / "These are my houses."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Arrange: people / Several / came / party / to / the', '["Several people came to the party", "Several came people to the party", "People several came to the party", "Several to the party people came"]', 0, 'Adjective before noun. Pattern: Several (quantitative) + people (noun) + verb. Correct: "Several people came."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which is correct?', '["What time is it?", "What is time it?", "Time what is it?", "What it is time?"]', 0, 'Interrogative adjective order: What + noun + verb. Correct: "What time is it?" Natural question word order.', 'medium'),

('foundation', 'adjectives', 'beginner', 'What is the error? "She has ideas creative."', '["Use: creative ideas (order)", "Use: creatively instead of creative", "Use: creativity instead of creative", "Nothing wrong"]', 0, 'Adjective before noun. Correct: "She has creative ideas." Pattern: adjective + noun (English word order).', 'medium'),

('foundation', 'adjectives', 'beginner', 'Rearrange: students / Few / passed / exam / the', '["Few students passed the exam", "Students few passed the exam", "Few passed students the exam", "Students passed few the exam"]', 0, 'Adjective before noun. Pattern: Few (quantitative) + students + verb. Correct: "Few students passed the exam."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose: "_____ car do you prefer?"', '["Which", "What", "Who", "Where"]', 0, 'Choice between options = Which. Pattern: Which + noun + verb? "What car" also OK but "Which" more specific (choosing).', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "I drank water little."', '["Use: little water (order)", "Use: few instead of little", "Use: less instead of little", "Nothing wrong"]', 0, 'Adjective before noun. Correct: "I drank little water." Pattern: little (uncountable) + noun. English word order!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which type? "The THIRD chapter is easy."', '["Numeral adjective", "Descriptive adjective", "Quantitative adjective", "Possessive adjective"]', 0, 'Ordinal numbers (first, second, third) = numeral adjectives. Show position/order. Pattern: ordinal + noun.', 'medium'),

-- HARD (5 questions)
('foundation', 'adjectives', 'beginner', 'Which is WRONG?', '["beautiful flowers", "flowers beautiful", "many books", "this house"]', 1, 'English: adjective BEFORE noun. "flowers beautiful" = wrong word order. Correct: "beautiful flowers."', 'hard'),

('foundation', 'adjectives', 'beginner', 'Arrange: water / enough / Have / we', '["Have we enough water", "We have enough water", "Enough water we have", "We have water enough"]', 1, '"Enough" exception: can come before OR after noun. "enough water" (before) OR "water enough" (after). Both OK but "before" more common: "We have enough water."', 'hard'),

('foundation', 'adjectives', 'beginner', 'Error: "All students the passed."', '["Use: All the students passed (order)", "Remove: the", "Use: The all students passed", "Nothing wrong"]', 0, 'Order: All + the + noun. Correct: "All the students passed." Pattern: quantifier + article + noun + verb.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Which is correct formal writing?', '["How much books?", "How many books?", "How much book?", "How many book?"]', 1, 'Countable plural = How many + plural noun. Correct: "How many books?" "How much" = uncountable only.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Identify ALL adjectives: "My two cats are very playful."', '["My, two", "My, two, very, playful", "My, two, playful", "two, playful"]', 2, 'Adjectives: My (possessive), two (numeral), playful (descriptive). "very" = adverb (modifies adjective playful). Pattern: 3 adjectives!', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: Order of Adjectives (25 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'adjectives', 'beginner', '"A _____ bag."', '["big red", "red big", "big and red", "red and big"]', 0, 'Order: Size before Color. Pattern: big (size) + red (color) + bag. Correct: "a big red bag."', 'easy'),

('foundation', 'adjectives', 'beginner', '"An _____ car."', '["old blue", "blue old", "old and blue", "blue and old"]', 0, 'Order: Age before Color. Pattern: old (age) + blue (color) + car. Correct: "an old blue car."', 'easy'),

('foundation', 'adjectives', 'beginner', '"A _____ table."', '["beautiful wooden", "wooden beautiful", "beautiful and wooden", "wooden and beautiful"]', 0, 'Order: Opinion before Material. Pattern: beautiful (opinion) + wooden (material) + table. Correct: "a beautiful wooden table."', 'easy'),

('foundation', 'adjectives', 'beginner', '"A _____ dress."', '["small silk", "silk small", "small and silk", "silk and small"]', 0, 'Order: Size before Material. Pattern: small (size) + silk (material) + dress. Correct: "a small silk dress."', 'easy'),

('foundation', 'adjectives', 'beginner', 'Order: Opinion → Size → Age → Color → Material → Noun. Which is correct?', '["a nice big house", "a big nice house", "a house big nice", "a house nice big"]', 0, 'Opinion before Size. Pattern: nice (opinion) + big (size) + house. Correct: "a nice big house."', 'easy'),

('foundation', 'adjectives', 'beginner', '"A _____ toy."', '["new plastic", "plastic new", "new and plastic", "plastic and new"]', 0, 'Order: Age before Material. Pattern: new (age) + plastic (material) + toy. Correct: "a new plastic toy."', 'easy'),

('foundation', 'adjectives', 'beginner', '"A _____ shirt."', '["red cotton", "cotton red", "red and cotton", "cotton and red"]', 0, 'Order: Color before Material. Pattern: red (color) + cotton (material) + shirt. Correct: "a red cotton shirt."', 'easy'),

('foundation', 'adjectives', 'beginner', 'Which comes first?', '["Opinion", "Color", "Size", "Material"]', 0, 'Order: Opinion → Size → Age → Color → Material. Opinion = first! (beautiful, ugly, nice, horrible).', 'easy'),

('foundation', 'adjectives', 'beginner', '"A _____ box."', '["large cardboard", "cardboard large", "large and cardboard", "cardboard and large"]', 0, 'Order: Size before Material. Pattern: large (size) + cardboard (material) + box. Correct: "a large cardboard box."', 'easy'),

('foundation', 'adjectives', 'beginner', '"The _____ building."', '["tall modern", "modern tall", "tall and modern", "modern and tall"]', 0, 'Order: Size before Age/Condition. Pattern: tall (size) + modern (age/type) + building. Correct: "the tall modern building."', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'adjectives', 'beginner', 'What is wrong? "A car red old."', '["Use: an old red car (order)", "Use: a red old car", "Use: an red old car", "Nothing wrong"]', 0, 'Order: Age → Color. Adjectives before noun. Correct: "an old red car." Pattern: age + color + noun.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose correct: "A _____ table."', '["beautiful round wooden", "round beautiful wooden", "wooden beautiful round", "round wooden beautiful"]', 0, 'Order: Opinion → Shape → Material. Pattern: beautiful (opinion) + round (shape) + wooden (material). Correct order!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "A leather black expensive jacket."', '["Use: an expensive black leather jacket", "Use: a black expensive leather jacket", "Use: a leather expensive black jacket", "Nothing wrong"]', 0, 'Order: Opinion → Color → Material. Correct: "an expensive (opinion) black (color) leather (material) jacket."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Arrange: bag / blue / A / big / cotton', '["A big blue cotton bag", "A blue big cotton bag", "A cotton blue big bag", "A big cotton blue bag"]', 0, 'Order: Size → Color → Material. Pattern: big + blue + cotton + bag. Correct: "A big blue cotton bag."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which is correct?', '["a lovely little old cottage", "a little lovely old cottage", "an old little lovely cottage", "a little old lovely cottage"]', 0, 'Order: Opinion → Size → Age. Pattern: lovely (opinion) + little (size) + old (age) + cottage. Natural flow!', 'medium'),

('foundation', 'adjectives', 'beginner', 'What is the error? "An Indian beautiful old temple."', '["Use: a beautiful old Indian temple", "Use: an old beautiful Indian temple", "Use: an Indian old beautiful temple", "Nothing wrong"]', 0, 'Order: Opinion → Age → Origin. Correct: "a beautiful (opinion) old (age) Indian (origin) temple."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Rearrange: dress / silk / red / new / A', '["A new red silk dress", "A red new silk dress", "A silk red new dress", "A red silk new dress"]', 0, 'Order: Age → Color → Material. Pattern: new + red + silk + dress. Correct: "A new red silk dress."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose: "The _____ car."', '["fast Italian sports", "Italian fast sports", "sports Italian fast", "Italian sports fast"]', 0, 'Order: Opinion/Quality → Origin → Purpose. Pattern: fast + Italian + sports + car. Correct order!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "A square big wooden box."', '["Use: a big square wooden box", "Use: a wooden big square box", "Use: a square wooden big box", "Nothing wrong"]', 0, 'Order: Size → Shape → Material. Correct: "a big (size) square (shape) wooden (material) box."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which follows correct order: Opinion → Size → Color → Material?', '["a nice small blue plastic toy", "a small nice blue plastic toy", "a blue small nice plastic toy", "a plastic blue small nice toy"]', 0, 'Correct: opinion (nice) → size (small) → color (blue) → material (plastic). Natural English order!', 'medium'),

-- HARD (5 questions)
('foundation', 'adjectives', 'beginner', 'Which is WRONG?', '["a big old brown house", "an expensive Italian leather bag", "a round wooden small table", "a beautiful long silk scarf"]', 2, 'Order: Size before Shape. Wrong: "round wooden small." Correct: "a small round wooden table." Size comes first!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Arrange: French / amazing / an / restaurant / old', '["An amazing old French restaurant", "An old amazing French restaurant", "A French amazing old restaurant", "An old French amazing restaurant"]', 0, 'Order: Opinion → Age → Origin. Pattern: amazing (opinion) + old (age) + French (origin) + restaurant. Perfect!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Error: "She wore a gold beautiful large ring."', '["Use: a beautiful large gold ring", "Use: a large beautiful gold ring", "Use: a gold large beautiful ring", "Nothing wrong"]', 0, 'Order: Opinion → Size → Material. Correct: "a beautiful (opinion) large (size) gold (material) ring."', 'hard'),

('foundation', 'adjectives', 'beginner', 'Which is correct formal writing? (Full order: Opinion → Size → Age → Shape → Color → Origin → Material → Purpose)', '["a nice small old round black Japanese wooden dining table", "a small nice old round black Japanese wooden dining table", "a black round old small nice Japanese wooden dining table", "an old small nice round black Japanese wooden dining table"]', 0, 'Correct order: opinion → size → age → shape → color → origin → material → purpose. First option follows complete rule!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Identify error: "A cotton Indian cheap shirt."', '["Use: a cheap Indian cotton shirt (Opinion→Origin→Material)", "Use: an Indian cheap cotton shirt", "Use: a cotton cheap Indian shirt", "Nothing wrong"]', 0, 'Order: Opinion → Origin → Material. Correct: "a cheap (opinion) Indian (origin) cotton (material) shirt."', 'hard'),

-- ============================================================================
-- SUBTOPIC 3: Degrees of Comparison (25 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'adjectives', 'beginner', '"She is _____ than me."', '["tall", "taller", "tallest", "more tall"]', 1, 'Comparative: -er (comparing two). tall → taller. Pattern: adjective + -er + than.', 'easy'),

('foundation', 'adjectives', 'beginner', '"He is the _____ in the class."', '["smart", "smarter", "smartest", "most smart"]', 2, 'Superlative: -est (comparing three+). smart → smartest. Pattern: the + adjective + -est.', 'easy'),

('foundation', 'adjectives', 'beginner', '"This book is _____ than that one."', '["easy", "easier", "easiest", "more easy"]', 1, 'Comparative: y → ier. easy → easier. Pattern: adjective ending in y + -ier + than.', 'easy'),

('foundation', 'adjectives', 'beginner', '"She is the _____ girl in school."', '["pretty", "prettier", "prettiest", "most pretty"]', 2, 'Superlative: y → iest. pretty → prettiest. Pattern: the + adjective + -iest.', 'easy'),

('foundation', 'adjectives', 'beginner', '"Today is _____ than yesterday."', '["hot", "hotter", "hottest", "more hot"]', 1, 'Comparative: double consonant + -er. hot → hotter. Pattern: CVC (consonant-vowel-consonant) doubles last letter.', 'easy'),

('foundation', 'adjectives', 'beginner', 'Comparative of "big":', '["biger", "bigger", "more big", "biggest"]', 1, 'Double consonant + -er. big → bigger. CVC pattern: double last consonant + -er.', 'easy'),

('foundation', 'adjectives', 'beginner', 'Superlative of "small":', '["smaller", "smallest", "most small", "more small"]', 1, 'One syllable: -est. small → smallest. Pattern: the + smallest.', 'easy'),

('foundation', 'adjectives', 'beginner', '"This is _____ than I thought."', '["hard", "harder", "hardest", "more hard"]', 1, 'Comparative: -er. hard → harder. Pattern: one syllable + -er + than.', 'easy'),

('foundation', 'adjectives', 'beginner', '"She is the _____ person I know."', '["nice", "nicer", "nicest", "most nice"]', 2, 'Superlative: e + -st. nice → nicest. Pattern: the + adjective + -st (when ends in e).', 'easy'),

('foundation', 'adjectives', 'beginner', 'One-syllable adjectives use:', '["-er / -est", "more / most", "less / least", "as / as"]', 0, 'Short adjectives (1 syllable): -er (comparative), -est (superlative). tall → taller → tallest.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'adjectives', 'beginner', 'What is wrong? "She is more tall than me."', '["Use: taller instead of more tall", "Use: tallest instead of more tall", "Use: most tall instead of more tall", "Nothing wrong"]', 0, 'One syllable = -er (not more). Correct: "She is taller than me." Pattern: one syllable + -er.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose correct: "This is the _____ day of my life."', '["happy", "happier", "happiest", "most happy"]', 2, 'Superlative: y → iest. happy → happiest. Pattern: the + happiest (two syllables ending in y).', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "He is the most fast runner."', '["Use: fastest instead of most fast", "Use: faster instead of most fast", "Use: more fast instead of most fast", "Nothing wrong"]', 0, 'One syllable = -est (not most). Correct: "He is the fastest runner." Pattern: one syllable + -est.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Arrange: taller / brother / is / My / me / than', '["My brother is taller than me", "My brother is more tall than me", "My brother is tallest than me", "My brother is tall than me"]', 0, 'Comparative: -er + than. Pattern: subject + is + adjective-er + than + object. Correct: "taller than me."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which is correct?', '["She is cleverer than him", "She is more clever than him", "Both A and B", "Neither A nor B"]', 2, 'Two syllables ending in -er/-y = both forms OK! "cleverer" OR "more clever" = both acceptable. British prefers -er.', 'medium'),

('foundation', 'adjectives', 'beginner', 'What is the error? "This is the popularest song."', '["Use: most popular instead of popularest", "Use: more popular instead of popularest", "Use: popular instead of popularest", "Nothing wrong"]', 0, 'Three syllables = most (not -est). Correct: "the most popular song." Pattern: long adjectives + most.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Rearrange: city / biggest / This / the / is', '["This is the biggest city", "This is the most big city", "This is the bigger city", "This is the big city"]', 0, 'Superlative: double consonant + -est. big → biggest. Pattern: the + biggest (CVC doubles).', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose: "English is _____ than Math."', '["easy", "easier", "easiest", "more easy"]', 1, 'Comparative: y → ier. easy → easier. Pattern: two syllables ending in y + -ier + than.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "She is the beautifulest girl."', '["Use: most beautiful instead of beautifulest", "Use: more beautiful instead of beautifulest", "Use: beautifuler instead of beautifulest", "Nothing wrong"]', 0, 'Three syllables = most (not -est). Correct: "the most beautiful girl." Pattern: long adjectives + most.', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which needs "-er" NOT "more"?', '["beautiful", "intelligent", "fast", "expensive"]', 2, 'One syllable = -er. "fast" → faster. Others (3 syllables) = more beautiful, more intelligent, more expensive.', 'medium'),

-- HARD (5 questions)
('foundation', 'adjectives', 'beginner', 'Which is WRONG?', '["the most difficult", "the difficultest", "the harder", "the easiest"]', 1, '"difficultest" is incorrect! Four syllables = most difficult (never -est). Pattern: long adjectives + most.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Arrange: intelligent / most / She / the / student / is', '["She is the most intelligent student", "She is the intelligentest student", "She is the more intelligent student", "She is the intelligenter student"]', 0, 'Four syllables = most (never -est). Correct: "the most intelligent student." Pattern: most + long adjective.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Error: "Today is more hot than yesterday."', '["Use: hotter instead of more hot", "Use: hottest instead of more hot", "Use: most hot instead of more hot", "Nothing wrong"]', 0, 'One syllable = -er (not more). Correct: "Today is hotter." CVC pattern: double t + -er.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Which is correct formal writing?', '["more happy", "happier", "Both correct", "Neither correct"]', 1, 'Two syllables ending in -y = -ier form (preferred). "happier" = standard. "more happy" = less common but grammatically OK.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Identify ALL errors: "She is the most pretty and more tall than me."', '["Use: prettiest, taller", "Use: prettier, tallest", "Use: prettiest, tallest", "Nothing wrong"]', 0, 'Two errors: "pretty" (2 syllables, -y) → prettiest (not most pretty). "tall" (1 syllable) → taller (not more tall). Correct: "the prettiest and taller."', 'hard'),

-- ============================================================================
-- SUBTOPIC 4: Irregular Comparisons (25 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'adjectives', 'beginner', 'Comparative of "good":', '["gooder", "better", "more good", "best"]', 1, 'Irregular! good → better → best. NOT gooder! Pattern: good (positive) → better (comparative).', 'easy'),

('foundation', 'adjectives', 'beginner', 'Superlative of "good":', '["goodest", "better", "best", "most good"]', 2, 'Irregular! good → better → best. NOT goodest! Pattern: good → better → best (complete change).', 'easy'),

('foundation', 'adjectives', 'beginner', 'Comparative of "bad":', '["badder", "worse", "more bad", "worst"]', 1, 'Irregular! bad → worse → worst. NOT badder! Pattern: bad (positive) → worse (comparative).', 'easy'),

('foundation', 'adjectives', 'beginner', 'Superlative of "bad":', '["baddest", "worse", "worst", "most bad"]', 2, 'Irregular! bad → worse → worst. NOT baddest! Pattern: bad → worse → worst (complete change).', 'easy'),

('foundation', 'adjectives', 'beginner', '"This is _____ than that."', '["good", "better", "best", "more good"]', 1, 'Comparative of good = better. Pattern: This is better than that. Irregular form!', 'easy'),

('foundation', 'adjectives', 'beginner', '"She is the _____ student."', '["good", "better", "best", "goodest"]', 2, 'Superlative of good = best. Pattern: the best. Irregular form!', 'easy'),

('foundation', 'adjectives', 'beginner', '"Today is _____ than yesterday."', '["bad", "worse", "worst", "more bad"]', 1, 'Comparative of bad = worse. Pattern: worse than. Irregular form!', 'easy'),

('foundation', 'adjectives', 'beginner', '"This is the _____ day ever."', '["bad", "worse", "worst", "baddest"]', 2, 'Superlative of bad = worst. Pattern: the worst. Irregular form!', 'easy'),

('foundation', 'adjectives', 'beginner', 'Irregular adjectives change:', '["completely (good→better)", "with -er/-est", "with more/most", "never"]', 0, 'Irregular = complete change! good → better, bad → worse, far → farther. NOT regular -er/-est pattern.', 'easy'),

('foundation', 'adjectives', 'beginner', 'Comparative of "far":', '["farer", "farther / further", "more far", "farthest"]', 1, 'Irregular! far → farther/further → farthest/furthest. Both forms correct! Pattern: farther (distance).', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'adjectives', 'beginner', 'What is wrong? "This is more good than that."', '["Use: better instead of more good", "Use: best instead of more good", "Use: gooder instead of more good", "Nothing wrong"]', 0, 'Irregular: good → better (not more good). Correct: "This is better than that." Never "more good"!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose correct: "Your idea is _____ than mine."', '["more bad", "badder", "worse", "worst"]', 2, 'Comparative of bad = worse (irregular). Pattern: worse than. Never "more bad" or "badder"!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "She is the goodest player."', '["Use: best instead of goodest", "Use: better instead of goodest", "Use: most good instead of goodest", "Nothing wrong"]', 0, 'Irregular: good → best (not goodest). Correct: "She is the best player." Superlative = best!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Arrange: is / worse / Health / than / his / mine', '["His health is worse than mine", "His health is more bad than mine", "His health is badder than mine", "His health is worst than mine"]', 0, 'Comparative of bad = worse. Pattern: worse than (irregular). Correct: "His health is worse than mine."', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which is correct?', '["farther distance", "further discussion", "Both correct", "Neither correct"]', 2, 'Both irregular forms! "farther" = physical distance. "further" = metaphorical/additional. Context determines usage!', 'medium'),

('foundation', 'adjectives', 'beginner', 'What is the error? "This is the most bad movie."', '["Use: worst instead of most bad", "Use: worse instead of most bad", "Use: baddest instead of most bad", "Nothing wrong"]', 0, 'Irregular: bad → worst (not most bad). Correct: "This is the worst movie." Superlative = worst!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Rearrange: better / is / option / This / the', '["This is the better option", "This is the best option", "This is the more good option", "Both A and B"]', 3, 'Context! Comparing two = better. Comparing three+ = best. "This is the better option" (of two) OR "the best option" (of many). Both valid!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Choose: "My score is _____ than yours."', '["more good", "gooder", "better", "best"]', 2, 'Comparative of good = better (irregular). Pattern: better than. Never "more good" or "gooder"!', 'medium'),

('foundation', 'adjectives', 'beginner', 'Error in: "She is the worse student in class."', '["Use: worst instead of worse", "Use: more bad instead of worse", "Use: baddest instead of worse", "Nothing wrong"]', 0, 'Comparing three+ = worst (superlative). Correct: "She is the worst student." "worse" = comparative (comparing two only).', 'medium'),

('foundation', 'adjectives', 'beginner', 'Which form is irregular?', '["tall → taller", "good → better", "fast → faster", "easy → easier"]', 1, 'Irregular = complete change. good → better (not gooder). Others follow regular -er pattern.', 'medium'),

-- HARD (5 questions)
('foundation', 'adjectives', 'beginner', 'Which is WRONG?', '["better than before", "the best result", "more good than expected", "the worst outcome"]', 2, '"more good" is incorrect! Irregular: good → better (not more good). All others correct irregular forms.', 'hard'),

('foundation', 'adjectives', 'beginner', 'Arrange: I / The / farther / walked / the / tired / more / felt', '["The farther I walked, the more tired I felt", "The more far I walked, the more tired I felt", "The farthest I walked, the most tired I felt", "The further I walked, the most tired I felt"]', 0, 'Double comparative pattern: The + comparative..., the + comparative... Correct: "The farther..., the more tired..." Both irregular and regular!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Error: "My English is getting more better."', '["Remove: more (use: better only)", "Use: best instead of more better", "Use: more good instead of more better", "Nothing wrong"]', 0, 'Double comparative = wrong! "better" already comparative. Correct: "My English is getting better." Never "more better"!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Which is correct formal writing?', '["elder brother", "older brother", "Both correct", "Neither correct"]', 2, 'Both correct! "elder" = family members (elder brother/sister). "older" = age (older brother/older car). Both irregular forms!', 'hard'),

('foundation', 'adjectives', 'beginner', 'Identify ALL irregular adjectives: "She is older, her work is better, and results are the best."', '["older, better, best", "better, best only", "older only", "None irregular"]', 1, 'Irregular: good → better → best. "old → older" = regular (old + -er). Only "better" and "best" are irregular forms!', 'hard');

